/**
 * Utility for retrieving the version of the ArcGIS Maps SDK for JavaScript.
 *
 * @since 4.0
 */

/**
 * The `major.minor` version of the ArcGIS Maps SDK for JavaScript.
 *
 * ```js
 * const esriNS = await $arcgis.import("@arcgis/core/kernel.js");
 * console.log(esriNS.version); // e.g. "5.0"
 * ```
 *
 * @default "5.0"
 */
export const version: string;

/**
 * The full version of the ArcGIS Maps SDK for JavaScript: `major.minor.patch` or `major.minor.0-next.N`.
 *
 * ```js
 * const esriNS = await $arcgis.import("@arcgis/core/kernel.js");
 * console.log(esriNS.fullVersion); // e.g. "5.0.0" or "5.0.0-next.1"
 * ```
 *
 * @since 4.27
 */
export const fullVersion: typeof version;